//! whisper-probe — native end-to-end proof that the gnosis Whisper engine
//! transcribes real audio (the mesh-tier baseline).
//!
//! Reference: arXiv 2212.04356 (Whisper — Robust Speech Recognition via
//! Large-Scale Weak Supervision, Radford et al. 2022).
//!
//! Pipeline exercised (the SAME code the mesh runs):
//!   1. fox audio:  `say` + `ffmpeg` → /tmp/whisper-ref/fox.f32  (16 kHz mono f32)
//!   2. mel:        n_fft=400 hop=160 80-mel log-mel, padded to 3000 frames
//!   3. weights:    HF whisper-tiny model.safetensors (fp32) via
//!                  `SafetensorsWhisperBackend` (HF→gnosis name map)
//!   4. encode:     `WhisperEncoder::forward`  (through the pipeline)
//!   5. generate:   the FIXED `generate()` — forced prefix
//!                  [50258,50259,50359,50363] then greedy to EOT 50257.
//!
//! Asserts the generated token ids equal the canonical fox sentence
//!   [264, 1702, 6292, 21026, 16704, 670, 264, 14847, 3000, 13]
//! ("the quick brown fox jumps over the lazy dog").
//!
//! Run:
//!   cargo run --release --bin whisper-probe -- \
//!       ./whisper-tiny-hf-root/model.safetensors
//!
//! Exit code 0 on PASS, 1 on FAIL.

use std::f32::consts::PI;
use std::path::Path;
use std::process::Command;

use distributed_inference::safetensors_whisper::SafetensorsWhisperBackend;
use distributed_inference::wasm_bindings_whisper::NativeWhisperPipeline;

// ── Whisper mel constants ────────────────────────────────────────────────
const N_FFT: usize = 400;
const HOP: usize = 160;
const N_MELS: usize = 80;
const N_FREQ: usize = N_FFT / 2 + 1; // 201
const N_SAMPLES: usize = 480_000; // 30 s @ 16 kHz
const N_FRAMES: usize = 3000;
const PAD: usize = N_FFT / 2; // 200, torch center=True reflect pad

const EOT: u32 = 50257;
const MAX_NEW_TOKENS: u32 = 64;

/// The canonical fox sentence token ids (multilingual whisper BPE).
/// "the quick brown fox jumps over the lazy dog"
const FOX_TOKENS: &[u32] = &[264, 1702, 6292, 21026, 16704, 670, 264, 14847, 3000, 13];

/// Embedded Slaney-normalized mel filterbank, row-major (80, 201) f32 —
/// the exact matrix HF `WhisperFeatureExtractor` uses.
static MEL_FILTERS_RAW: &[u8] = include_bytes!("../../assets/mel_filters_80_201.f32");

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let weights_path = args.get(1).cloned().unwrap_or_else(|| {
        // Default to the repo's whisper-tiny safetensors root.
        "./whisper-tiny-hf-root/model.safetensors".to_string()
    });

    println!("== whisper-probe (gnosis native mesh baseline) ==");
    println!("weights: {weights_path}");

    // ── 1. fox audio ─────────────────────────────────────────────────────
    let audio = match load_or_make_fox_audio() {
        Ok(a) => a,
        Err(e) => {
            eprintln!("FAIL: could not obtain fox audio: {e}");
            std::process::exit(1);
        }
    };
    println!(
        "audio:   {} samples ({:.2} s @ 16 kHz)",
        audio.len(),
        audio.len() as f32 / 16000.0
    );

    // ── 2. mel ───────────────────────────────────────────────────────────
    let t_mel = std::time::Instant::now();
    let mel = log_mel_spectrogram(&audio);
    println!(
        "mel:     {} values (80x3000) in {:?}",
        mel.len(),
        t_mel.elapsed()
    );

    // ── 3. weights ───────────────────────────────────────────────────────
    if !Path::new(&weights_path).exists() {
        eprintln!("FAIL: weights file not found: {weights_path}");
        eprintln!("      fetch HF openai/whisper-tiny model.safetensors (fp32, ~151 MB).");
        std::process::exit(1);
    }
    let t_load = std::time::Instant::now();
    let bytes = std::fs::read(&weights_path).expect("read weights");
    let (backend, config) = match SafetensorsWhisperBackend::from_safetensors_bytes(&bytes) {
        Ok(v) => v,
        Err(e) => {
            eprintln!("FAIL: safetensors load: {e}");
            std::process::exit(1);
        }
    };
    println!(
        "config:  tiny? enc_layers={} dec_layers={} hidden={} heads={} vocab={} (loaded in {:?})",
        config.encoder_layers,
        config.decoder_layers,
        config.encoder_hidden_dim,
        config.encoder_heads,
        config.vocab_size,
        t_load.elapsed()
    );

    let backend: std::sync::Arc<dyn distributed_inference::loader::WeightBackend> =
        std::sync::Arc::new(backend);
    let mut pipeline = NativeWhisperPipeline::new(backend, config);

    // ── 4. encode ────────────────────────────────────────────────────────
    let t_enc = std::time::Instant::now();
    let encoder_out = pipeline.encode(&mel);
    println!(
        "encode:  {} values in {:?}",
        encoder_out.len(),
        t_enc.elapsed()
    );

    // ── 5. generate (the FIXED forced-prefix greedy loop) ────────────────
    let t_gen = std::time::Instant::now();
    let tokens = pipeline.generate(&encoder_out, MAX_NEW_TOKENS, EOT);
    let gen_dt = t_gen.elapsed();
    println!("generate: {} tokens in {:?}", tokens.len(), gen_dt);

    println!();
    println!("expected: {FOX_TOKENS:?}");
    println!("actual:   {tokens:?}");

    if tokens == FOX_TOKENS {
        println!();
        println!("PASS — gnosis native whisper transcribed the fox correctly.");
        std::process::exit(0);
    } else {
        println!();
        println!("FAIL — token mismatch (see expected vs actual above).");
        std::process::exit(1);
    }
}

// ─────────────────────────────────────────────────────────────────────────
// fox audio: say + ffmpeg → /tmp/whisper-ref/fox.f32
// ─────────────────────────────────────────────────────────────────────────

fn load_or_make_fox_audio() -> Result<Vec<f32>, String> {
    let dir = "/tmp/whisper-ref";
    let f32_path = format!("{dir}/fox.f32");

    if Path::new(&f32_path).exists() {
        let bytes = std::fs::read(&f32_path).map_err(|e| e.to_string())?;
        return Ok(le_bytes_to_f32(&bytes));
    }

    std::fs::create_dir_all(dir).map_err(|e| e.to_string())?;
    let aiff = format!("{dir}/fox.aiff");
    let wav = format!("{dir}/fox.wav");

    // 1. macOS `say` → AIFF. The sentence must match the FOX_TOKENS target.
    let say = Command::new("say")
        .args([
            "-v",
            "Samantha",
            "-o",
            &aiff,
            "The quick brown fox jumps over the lazy dog.",
        ])
        .status()
        .map_err(|e| format!("`say` failed to launch: {e}"))?;
    if !say.success() {
        return Err("`say` exited non-zero".into());
    }

    // 2. ffmpeg → 16 kHz mono f32le raw (and a wav for inspection).
    let ff = Command::new("ffmpeg")
        .args([
            "-y", "-i", &aiff, "-ar", "16000", "-ac", "1", "-f", "f32le", &f32_path,
        ])
        .status()
        .map_err(|e| format!("ffmpeg(f32) failed to launch: {e}"))?;
    if !ff.success() {
        return Err("ffmpeg(f32) exited non-zero".into());
    }
    // Best-effort wav (ignore failure — not needed for the probe).
    let _ = Command::new("ffmpeg")
        .args(["-y", "-i", &aiff, "-ar", "16000", "-ac", "1", &wav])
        .status();

    let bytes = std::fs::read(&f32_path).map_err(|e| e.to_string())?;
    Ok(le_bytes_to_f32(&bytes))
}

fn le_bytes_to_f32(b: &[u8]) -> Vec<f32> {
    let n = b.len() / 4;
    let mut out = Vec::with_capacity(n);
    for i in 0..n {
        out.push(f32::from_le_bytes([
            b[4 * i],
            b[4 * i + 1],
            b[4 * i + 2],
            b[4 * i + 3],
        ]));
    }
    out
}

// ─────────────────────────────────────────────────────────────────────────
// Whisper log-mel spectrogram (byte-equivalent to HF, naive 400-pt DFT)
// ─────────────────────────────────────────────────────────────────────────

fn log_mel_spectrogram(audio: &[f32]) -> Vec<f32> {
    // 1. pad/truncate to exactly N_SAMPLES.
    let mut wav = vec![0.0f32; N_SAMPLES];
    let take = audio.len().min(N_SAMPLES);
    wav[..take].copy_from_slice(&audio[..take]);

    // 2. reflect-pad PAD samples each side (torch.stft center=True).
    let padded_len = N_SAMPLES + 2 * PAD;
    let mut padded = vec![0.0f32; padded_len];
    for i in 0..padded_len {
        let src = reflect_index(i as isize - PAD as isize, N_SAMPLES);
        padded[i] = wav[src];
    }

    // periodic Hann window (matches torch.hann_window(N_FFT)).
    let window: Vec<f32> = (0..N_FFT)
        .map(|n| 0.5 * (1.0 - (2.0 * PI * n as f32 / N_FFT as f32).cos()))
        .collect();

    // precompute DFT trig tables (real/imag) for the naive 400-pt DFT.
    // cos_t[k*N_FFT + n], sin_t[k*N_FFT + n] for k in 0..N_FREQ, n in 0..N_FFT.
    let mut cos_t = vec![0.0f32; N_FREQ * N_FFT];
    let mut sin_t = vec![0.0f32; N_FREQ * N_FFT];
    for k in 0..N_FREQ {
        for n in 0..N_FFT {
            let ang = -2.0 * PI * (k as f32) * (n as f32) / (N_FFT as f32);
            cos_t[k * N_FFT + n] = ang.cos();
            sin_t[k * N_FFT + n] = ang.sin();
        }
    }

    // 3. STFT power spectrum per frame: |X(k)|^2, shape (201, 3000).
    let mut mag = vec![0.0f32; N_FREQ * N_FRAMES];
    let mut windowed = vec![0.0f32; N_FFT];
    for f in 0..N_FRAMES {
        let start = f * HOP;
        for i in 0..N_FFT {
            windowed[i] = padded[start + i] * window[i];
        }
        for k in 0..N_FREQ {
            let cos_row = &cos_t[k * N_FFT..(k + 1) * N_FFT];
            let sin_row = &sin_t[k * N_FFT..(k + 1) * N_FFT];
            let mut re = 0.0f32;
            let mut im = 0.0f32;
            for n in 0..N_FFT {
                re += windowed[n] * cos_row[n];
                im += windowed[n] * sin_row[n];
            }
            mag[k * N_FRAMES + f] = re * re + im * im;
        }
    }

    // 4. mel_spec = mel_filters(80,201) @ magnitudes(201,3000) → (80,3000).
    let mel_filters = mel_filters();
    let mut log_spec = vec![0.0f32; N_MELS * N_FRAMES];
    for m in 0..N_MELS {
        let filt = &mel_filters[m * N_FREQ..(m + 1) * N_FREQ];
        for f in 0..N_FRAMES {
            let mut acc = 0.0f32;
            for k in 0..N_FREQ {
                acc += filt[k] * mag[k * N_FRAMES + f];
            }
            log_spec[m * N_FRAMES + f] = acc.max(1e-10).log10();
        }
    }

    // 5. clamp to (max - 8); 6. (max(.,floor) + 4) / 4.
    let mut max_val = f32::NEG_INFINITY;
    for &v in log_spec.iter() {
        if v > max_val {
            max_val = v;
        }
    }
    let floor = max_val - 8.0;
    for v in log_spec.iter_mut() {
        let clamped = if *v < floor { floor } else { *v };
        *v = (clamped + 4.0) / 4.0;
    }

    log_spec
}

#[inline]
fn reflect_index(mut idx: isize, len: usize) -> usize {
    if len == 1 {
        return 0;
    }
    let n = len as isize;
    let period = 2 * (n - 1);
    idx = idx.rem_euclid(period);
    if idx >= n {
        idx = period - idx;
    }
    idx as usize
}

fn mel_filters() -> Vec<f32> {
    assert_eq!(MEL_FILTERS_RAW.len(), N_MELS * N_FREQ * 4);
    le_bytes_to_f32(MEL_FILTERS_RAW)
}
